227: /**
228:  * Per route settings for ExtAuth. Allows customizing the CheckRequest on a
229:  * virtualhost\route\weighted cluster level.
230:  */
231: class FilterConfigPerRoute : public Router::RouteSpecificFilterConfig {
232: public:
233:   using ContextExtensionsMap = Protobuf::Map<std::string, std::string>;
234: 
235:   FilterConfigPerRoute(
236:       const envoy::extensions::filters::http::ext_authz::v3::ExtAuthzPerRoute& config)
237:       : context_extensions_(config.has_check_settings()
238:                                 ? config.check_settings().context_extensions()
239:                                 : ContextExtensionsMap()),
240:         check_settings_(config.has_check_settings()
241:                             ? config.check_settings()
242:                             : envoy::extensions::filters::http::ext_authz::v3::CheckSettings()),
243:         disabled_(config.disabled()) {
244:     if (config.has_check_settings() && config.check_settings().disable_request_body_buffering() &&
245:         config.check_settings().has_with_request_body()) {
246:       ExceptionUtil::throwEnvoyException(
247:           "Invalid configuration for check_settings. Only one of disable_request_body_buffering or "
248:           "with_request_body can be set.");
249:     }
250:   }
251: 
252:   void merge(const FilterConfigPerRoute& other);
253: 
254:   /**
255:    * @return Context extensions to add to the CheckRequest.
256:    */
257:   const ContextExtensionsMap& contextExtensions() const { return context_extensions_; }
258:   // Allow moving the context extensions out of this object.
259:   ContextExtensionsMap&& takeContextExtensions() { return std::move(context_extensions_); }
260: 
261:   bool disabled() const { return disabled_; }
262: 
263:   envoy::extensions::filters::http::ext_authz::v3::CheckSettings checkSettings() const {
264:     return check_settings_;
265:   }
266: 
267: private:
268:   // We save the context extensions as a protobuf map instead of a std::map as this allows us to
269:   // move it to the CheckRequest, thus avoiding a copy that would incur by converting it.
270:   ContextExtensionsMap context_extensions_;
271:   envoy::extensions::filters::http::ext_authz::v3::CheckSettings check_settings_;
272:   bool disabled_;
273: };
