63: FilterConfig::FilterConfig(const envoy::extensions::filters::http::ext_authz::v3::ExtAuthz& config,
64:                            Stats::Scope& scope, const std::string& stats_prefix,
65:                            Server::Configuration::ServerFactoryContext& factory_context)
66:     : allow_partial_message_(config.with_request_body().allow_partial_message()),
67:       failure_mode_allow_(config.failure_mode_allow()),
68:       failure_mode_allow_header_add_(config.failure_mode_allow_header_add()),
69:       clear_route_cache_(config.clear_route_cache()),
70:       max_request_bytes_(config.with_request_body().max_request_bytes()),
71: 
