303:                        *decoder_callbacks_);
304:       initiateCall(*request_headers_);
305:     }
306:     return filter_return_ == FilterReturn::StopDecoding ? Http::FilterTrailersStatus::StopIteration
307:                                                         : Http::FilterTrailersStatus::Continue;
308:   }
309: 
